        gameRegistry = _gameRegistry;
        router       = _router;
        settler      = msg.sender;
        winnersPerRound = 3;
        protocolCutBps  = 200;
    }

    // ─── Game Lifecycle ───────────────────────────────────────────────────────

    function startGame() external onlyOwner {
