    function getCurrentWindow() public view returns (bytes6 window) {
        bytes memory result = new bytes(6);
        for (uint256 i = 1; i <= SEGMENTS_PER_ROUND; i++) {
            uint8 idx = uint8(i - 1);
            if (i < currentSegment) {
                // Locked digit
                result[idx] = ALPHABET[segmentDigitCounter[i] % 36];
            } else if (i == currentSegment) {
