        currentRound++;
        currentSegment   = 1;
        segmentStartTime = block.timestamp;
        for (uint256 i = 1; i <= SEGMENTS_PER_ROUND; i++) {
            segmentDigitCounter[i] = 0;
            segmentDigitLocked[i]  = false;
